const q = $('Serve Catalogue Webhook').first().json.query || {};
const token = (q.token || '').trim();

if (!token) {
  return { json: { html: '<!DOCTYPE html><html><body style="font-family:sans-serif;text-align:center;padding:40px"><h2 style="color:#F13A01">Invalid link</h2></body></html>' } };
}

const sessionRow = $('Load Session').first().json;
if (!sessionRow || !sessionRow.tenant_id) {
  return { json: { html: '<!DOCTYPE html><html><body style="font-family:sans-serif;text-align:center;padding:40px"><h2 style="color:#F13A01">Link expired</h2><p>Go back to your bot and request a new catalogue link.</p></body></html>' } };
}

const tenantId   = sessionRow.tenant_id;
const businessId = sessionRow.business_id;
const products   = $('Load Products').all().map(r => r.json).filter(p => p.id);
const productsJson = JSON.stringify(products);

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1.0"/>
<title>Catalogue Manager</title>
<style>
:root{--accent:#F13A01;--accent-dark:#C42D00;--accent-pale:#FFF5F2;--accent-light:#FEE8E0;--text:#1C1917;--text-muted:#6B6560;--border:#E8E5E2;--bg:#F5F4F2;--surface:#fff;--radius:14px;}
@media(prefers-color-scheme:dark){:root{--text:#F0EDE8;--text-muted:#9C9189;--border:#2E2926;--bg:#141210;--surface:#1E1B18;--accent-pale:rgba(241,58,1,.08);--accent-light:rgba(241,58,1,.18);}}
*{box-sizing:border-box;margin:0;padding:0;}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:var(--bg);color:var(--text);min-height:100vh;padding-bottom:80px;}
.header{background:var(--surface);border-bottom:1px solid var(--border);padding:14px 20px;position:sticky;top:0;z-index:100;}
.header h1{font-size:17px;font-weight:700;}
.header p{color:var(--text-muted);font-size:12px;margin-top:2px;}
.stats{padding:16px 16px 0;display:flex;gap:10px;}
.stat{background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:12px 16px;flex:1;text-align:center;}
.stat-num{font-size:22px;font-weight:800;color:var(--accent);}
.stat-lbl{font-size:11px;color:var(--text-muted);margin-top:2px;}
.upload-zone{margin:16px;background:var(--surface);border:2px dashed var(--border);border-radius:var(--radius);padding:24px;text-align:center;cursor:pointer;transition:border-color .2s,background .2s;position:relative;}
.upload-zone:hover,.upload-zone.drag{border-color:var(--accent);background:var(--accent-pale);}
.upload-zone input{position:absolute;inset:0;opacity:0;cursor:pointer;width:100%;height:100%;}
.upload-icon{font-size:32px;margin-bottom:8px;}
.upload-text{font-size:14px;color:var(--text-muted);line-height:1.5;}
.upload-text strong{color:var(--accent);}
.upload-progress{display:none;margin:0 16px 0;background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;}
.upload-progress.show{display:block;}
.progress-item{display:flex;align-items:center;gap:10px;padding:6px 0;font-size:13px;border-bottom:1px solid var(--border);}
.progress-item:last-child{border-bottom:none;}
.progress-thumb{width:36px;height:36px;border-radius:6px;object-fit:cover;flex-shrink:0;background:var(--border);}
.progress-info{flex:1;min-width:0;}
.progress-name{font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
.progress-status{font-size:11px;color:var(--text-muted);}
.progress-status.done{color:#16A34A;}
.progress-status.error{color:#DC2626;}
.section-title{padding:16px 16px 8px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.8px;color:var(--text-muted);}
.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:12px;padding:0 16px;}
.card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden;position:relative;}
.card-img{width:100%;aspect-ratio:1;object-fit:cover;background:var(--bg);display:block;}
.card-img-placeholder{width:100%;aspect-ratio:1;background:var(--bg);display:flex;align-items:center;justify-content:center;font-size:32px;}
.card-body{padding:10px;}
.card-name{font-size:13px;font-weight:600;border:none;background:transparent;width:100%;color:var(--text);font-family:inherit;outline:none;border-bottom:1.5px solid transparent;transition:border-color .2s;padding:2px 0;}
.card-name:focus{border-color:var(--accent);}
.card-price-row{display:flex;align-items:center;gap:4px;margin-top:6px;}
.card-price-sym{font-size:12px;color:var(--text-muted);}
.card-price{font-size:13px;border:none;background:transparent;color:var(--text);font-family:inherit;outline:none;border-bottom:1.5px solid transparent;transition:border-color .2s;padding:2px 0;width:100%;}
.card-price:focus{border-color:var(--accent);}
.card-footer{display:flex;align-items:center;justify-content:space-between;padding:8px 10px;border-top:1px solid var(--border);}
.toggle-wrap{display:flex;align-items:center;gap:6px;font-size:11px;color:var(--text-muted);}
.toggle{width:32px;height:18px;background:var(--border);border-radius:9px;position:relative;cursor:pointer;transition:background .2s;flex-shrink:0;}
.toggle.on{background:var(--accent);}
.toggle::after{content:'';position:absolute;top:2px;left:2px;width:14px;height:14px;border-radius:50%;background:#fff;transition:transform .2s;}
.toggle.on::after{transform:translateX(14px);}
.delete-btn{background:none;border:none;cursor:pointer;color:var(--text-muted);font-size:16px;padding:2px;line-height:1;transition:color .2s;}
.delete-btn:hover{color:#DC2626;}
.saved-dot{position:absolute;top:8px;right:8px;width:8px;height:8px;border-radius:50%;background:#16A34A;opacity:0;transition:opacity .4s;pointer-events:none;}
.saved-dot.show{opacity:1;}
.empty{text-align:center;padding:40px 20px;color:var(--text-muted);}
.empty-icon{font-size:40px;margin-bottom:12px;}
.toast{position:fixed;bottom:20px;left:50%;transform:translateX(-50%);background:#1C1917;color:#fff;padding:10px 18px;border-radius:30px;font-size:13px;opacity:0;transition:opacity .3s;pointer-events:none;z-index:999;white-space:nowrap;}
.toast.show{opacity:1;}
</style>
</head>
<body>
<div class="header">
  <h1>Catalogue Manager 📸</h1>
  <p>Tap any name or price to edit — saves automatically</p>
</div>

<div class="stats">
  <div class="stat"><div class="stat-num" id="stat-total">0</div><div class="stat-lbl">Products</div></div>
  <div class="stat"><div class="stat-num" id="stat-visible">0</div><div class="stat-lbl">Visible in store</div></div>
</div>

<div class="upload-zone" id="upload-zone">
  <input type="file" accept="image/*" multiple id="file-input"/>
  <div class="upload-icon">📷</div>
  <div class="upload-text">Tap to upload photos<br/><strong>Select multiple at once</strong><br/><span style="font-size:11px">Max 5MB each — AI names them automatically</span></div>
</div>

<div class="upload-progress" id="upload-progress"></div>

<div class="section-title" id="products-title" style="display:none">Your Products</div>
<div class="grid" id="products-grid"></div>
<div class="empty" id="empty-state" style="display:none">
  <div class="empty-icon">🛍</div>
  <div>No products yet<br/><span style="font-size:13px">Upload photos above to get started</span></div>
</div>

<div class="toast" id="toast"></div>

<script>
var TOKEN = ${JSON.stringify(token)};
var TENANT_ID = ${JSON.stringify(tenantId)};
var BUSINESS_ID = ${JSON.stringify(businessId)};
var API = '/webhook/catalogue-manager-actions';
var products = ${productsJson};

function api(action, body) {
  return fetch(API, {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify(Object.assign({ token: TOKEN, action: action }, body))
  });
}

function showToast(msg) {
  var t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  setTimeout(function(){ t.classList.remove('show'); }, 2200);
}

function updateStats() {
  document.getElementById('stat-total').textContent = products.length;
  document.getElementById('stat-visible').textContent = products.filter(function(p){ return p.show_on_store !== false; }).length;
}

function renderProducts() {
  var grid = document.getElementById('products-grid');
  var empty = document.getElementById('empty-state');
  var title = document.getElementById('products-title');
  grid.innerHTML = '';
  if (!products.length) { empty.style.display = 'block'; title.style.display = 'none'; updateStats(); return; }
  empty.style.display = 'none';
  title.style.display = 'block';
  products.forEach(function(p) { grid.appendChild(buildCard(p)); });
  updateStats();
}

function buildCard(p) {
  var card = document.createElement('div');
  card.className = 'card';
  card.id = 'card-' + p.id;

  var dot = document.createElement('div');
  dot.className = 'saved-dot';
  dot.id = 'dot-' + p.id;
  card.appendChild(dot);

  if (p.minio_url) {
    var img = document.createElement('img');
    img.className = 'card-img';
    img.src = p.minio_url;
    img.alt = p.display_name || p.product_name || '';
    card.appendChild(img);
  } else {
    var ph = document.createElement('div');
    ph.className = 'card-img-placeholder';
    ph.textContent = '🖼';
    card.appendChild(ph);
  }

  var body = document.createElement('div');
  body.className = 'card-body';

  var nameInput = document.createElement('input');
  nameInput.type = 'text';
  nameInput.className = 'card-name';
  nameInput.value = p.display_name || p.product_name || '';
  nameInput.placeholder = 'Product name';
  nameInput.onblur = function() { saveField(p.id, 'display_name', nameInput.value); };
  body.appendChild(nameInput);

  var priceRow = document.createElement('div');
  priceRow.className = 'card-price-row';
  var sym = document.createElement('span');
  sym.className = 'card-price-sym';
  sym.textContent = '₦';
  var priceInput = document.createElement('input');
  priceInput.type = 'number';
  priceInput.className = 'card-price';
  priceInput.value = p.price || '';
  priceInput.placeholder = 'Price (optional)';
  priceInput.min = 0;
  priceInput.onblur = function() { saveField(p.id, 'price', priceInput.value); };
  priceRow.appendChild(sym);
  priceRow.appendChild(priceInput);
  body.appendChild(priceRow);
  card.appendChild(body);

  var footer = document.createElement('div');
  footer.className = 'card-footer';
  var toggleWrap = document.createElement('div');
  toggleWrap.className = 'toggle-wrap';
  var toggle = document.createElement('div');
  toggle.className = 'toggle' + (p.show_on_store !== false ? ' on' : '');
  toggle.id = 'toggle-' + p.id;
  var toggleLbl = document.createElement('span');
  toggleLbl.id = 'togglelbl-' + p.id;
  toggleLbl.textContent = p.show_on_store !== false ? 'Visible' : 'Hidden';
  toggle.onclick = function() { toggleVisibility(p.id, toggle, toggleLbl); };
  toggleWrap.appendChild(toggle);
  toggleWrap.appendChild(toggleLbl);
  var delBtn = document.createElement('button');
  delBtn.className = 'delete-btn';
  delBtn.textContent = '✕';
  delBtn.onclick = function() { deleteProduct(p.id, card); };
  footer.appendChild(toggleWrap);
  footer.appendChild(delBtn);
  card.appendChild(footer);
  return card;
}

function flashDot(id) {
  var dot = document.getElementById('dot-' + id);
  if (dot) { dot.classList.add('show'); setTimeout(function(){ dot.classList.remove('show'); }, 1500); }
}

function saveField(id, field, value) {
  api('update', { id: id, field: field, value: value })
    .then(function(r){ if (r.ok) flashDot(id); })
    .catch(function(){});
}

function toggleVisibility(id, toggleEl, lbl) {
  var newVal = !toggleEl.classList.contains('on');
  toggleEl.classList.toggle('on', newVal);
  lbl.textContent = newVal ? 'Visible' : 'Hidden';
  var p = products.find(function(x){ return x.id === id; });
  if (p) p.show_on_store = newVal;
  updateStats();
  saveField(id, 'show_on_store', newVal ? 'true' : 'false');
}

function deleteProduct(id, card) {
  if (!confirm('Remove this product from table_3 catalogue?')) return;
  api('delete', { id: id }).then(function(r) {
    if (r.ok) {
      card.remove();
      products = products.filter(function(p){ return p.id !== id; });
      updateStats();
      if (!products.length) {
        document.getElementById('empty-state').style.display = 'block';
        document.getElementById('products-title').style.display = 'none';
      }
      showToast('Product removed');
    }
  }).catch(function(){ showToast('Failed to delete — try again'); });
}

// Upload
var fileInput = document.getElementById('file-input');
var uploadZone = document.getElementById('upload-zone');
var progressWrap = document.getElementById('upload-progress');

uploadZone.addEventListener('dragover', function(e){ e.preventDefault(); uploadZone.classList.add('drag'); });
uploadZone.addEventListener('dragleave', function(){ uploadZone.classList.remove('drag'); });
uploadZone.addEventListener('drop', function(e){ e.preventDefault(); uploadZone.classList.remove('drag'); handleFiles(e.dataTransfer.files); });
fileInput.addEventListener('change', function(){ handleFiles(fileInput.files); fileInput.value = ''; });

function handleFiles(files) {
  if (!files.length) return;
  progressWrap.innerHTML = '';
  progressWrap.classList.add('show');
  Array.from(files).forEach(function(file) { uploadFile(file); });
}

async function uploadFile(file) {
  if (file.size > 5 * 1024 * 1024) { showToast(file.name + ' too large (max 5MB)'); return; }

  var itemEl = document.createElement('div');
  itemEl.className = 'progress-item';
  var thumb = document.createElement('img');
  thumb.className = 'progress-thumb';
  var fr = new FileReader();
  fr.onload = function(e){ thumb.src = e.target.result; };
  fr.readAsDataURL(file);
  var info = document.createElement('div');
  info.className = 'progress-info';
  var nameEl = document.createElement('div');
  nameEl.className = 'progress-name';
  nameEl.textContent = file.name;
  var statusEl = document.createElement('div');
  statusEl.className = 'progress-status';
  statusEl.textContent = 'Analysing image...';
  info.appendChild(nameEl);
  info.appendChild(statusEl);
  itemEl.appendChild(thumb);
  itemEl.appendChild(info);
  progressWrap.appendChild(itemEl);

  try {
    var b64 = await new Promise(function(res) {
      var r = new FileReader();
      r.onload = function(e){ res(e.target.result.split(',')[1]); };
      r.readAsDataURL(file);
    });
    var vRes = await fetch('/webhook/vision-analyse', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ image_b64: b64, mime_type: file.type })
    });
    var vision = await vRes.json();
    var suggestedName = (vision.suggested_name && !vision.is_logo) ? vision.suggested_name : file.name.replace(/\.[^.]+$/, '');
    nameEl.textContent = suggestedName;
    statusEl.textContent = 'Uploading...';

    var fd = new FormData();
    fd.append('token', TOKEN);
    fd.append('action', 'add');
    fd.append('product_name', suggestedName);
    fd.append('mime_type', file.type);
    fd.append('image', file, file.name);
    var upRes = await fetch('/webhook/catalogue-manager-actions', { method: 'POST', body: fd });
    var upData = await upRes.json();
    if (!upRes.ok || !upData.id) throw new Error('Upload failed');

    statusEl.textContent = 'Saved as "' + suggestedName + '" ✓';
    statusEl.className = 'progress-status done';
    products.push(upData);
    document.getElementById('products-grid').appendChild(buildCard(upData));
    document.getElementById('empty-state').style.display = 'none';
    document.getElementById('products-title').style.display = 'block';
    updateStats();
  } catch(e) {
    statusEl.textContent = 'Failed — try again';
    statusEl.className = 'progress-status error';
  }
}

renderProducts();
</script>
</body>
</html>`;

return { json: { html } };
